    """
    Helper method used by `toJson()` to serialize this object.
    """
    try:
        if isinstance(obj, mqtt.Client) or isinstance(obj, Thread):
            return ""
        if (
            str(obj.__class__).replace("&lt;class '", "").replace("'&gt;", "")
            == "mappingproxy"
